import { useState, useEffect, useCallback, useRef } from "react";
import { locales } from "./locales";
import {
  ALL_CHARS, ALL_RADICALS,
  filterChars, defaultRadicals,
  generateQuizPool, generateQuestion,
  parseMarkdownImport,
} from "./data/gameEngine";


import './styles/components.css';

// ─── 畫面元件 ────────────────────────────────────────────────────
import HomeScreen from "./components/HomeScreen";
import RadicalSelect from "./components/RadicalSelect";
import QuizScreen from "./components/QuizScreen";
import ResultScreen from "./components/ResultScreen";
import ForgeScreen from "./components/ForgeScreen";
import PolyphoneScreen from "./components/PolyphoneScreen";

// ─── 格式化時間 ──────────────────────────────────────────────────
function formatTime(sec) {
  if (sec <= 0) return "0:00";
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

// ═══════════════════════════════════════════════════════════════════
export default function HanziApp() {
  // ─── 基本狀態 ──────────────────────────────────────────────────
  const [lang, setLang] = useState("zh");
  const t = locales[lang];

  const [screen, setScreen] = useState("home");
  const [level, setLevel] = useState(1);
  const [selectedRadicals, setSelectedRadicals] = useState(() => defaultRadicals());
  const [radicalSearch, setRadicalSearch] = useState("");
  const [timerValue, setTimerValue] = useState(180);
  const [importText, setImportText] = useState("");
  const [showImportModal, setShowImportModal] = useState(false);

  // ─── 測驗狀態 ──────────────────────────────────────────────────
  const [quizPool, setQuizPool] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [question, setQuestion] = useState(null);
  const [selected, setSelected] = useState(null);
  const [firstAttemptCorrect, setFirstAttemptCorrect] = useState(null);
  const [wrongSelections, setWrongSelections] = useState(new Set());
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [bestStreak, setBestStreak] = useState(0);
  const [total, setTotal] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [timeLeft, setTimeLeft] = useState(0);
  const [earlyEnd, setEarlyEnd] = useState(false);
  const [earlyEndTime, setEarlyEndTime] = useState(null);
  const [animKey, setAnimKey] = useState(0);
  const [questionStartTime, setQuestionStartTime] = useState(null);
  const [questionTimes, setQuestionTimes] = useState([]);
  const quizLevelRef = useRef(1);
  const timerRef = useRef(null);

  // ─── 造字工坊狀態 ──────────────────────────────────────────────
  const [forgePool, setForgePool] = useState([]);
  const [forgeIdx, setForgeIdx] = useState(0);
  const [forgeQuestion, setForgeQuestion] = useState(null);
  const [forgeSelected, setForgeSelected] = useState(null);
  const [forgeScore, setForgeScore] = useState(0);
  const [forgeTotal, setForgeTotal] = useState(0);
  const [forgeWrongs, setForgeWrongs] = useState(new Set());
  const [forgeResult, setForgeResult] = useState(false);
  const [forgeAnimKey, setForgeAnimKey] = useState(0);
  const [forgeHistory, setForgeHistory] = useState([]);

  // ─── 變聲秘術狀態 ──────────────────────────────────────────────
  const [polyPool, setPolyPool] = useState([]);
  const [polyIdx, setPolyIdx] = useState(0);
  const [polyQuestion, setPolyQuestion] = useState(null);
  const [polySelected, setPolySelected] = useState(null);
  const [polyScore, setPolyScore] = useState(0);
  const [polyTotal, setPolyTotal] = useState(0);
  const [polyWrongs, setPolyWrongs] = useState(new Set());
  const [polyResult, setPolyResult] = useState(false);
  const [polyAnimKey, setPolyAnimKey] = useState(0);
  const [polyHistory, setPolyHistory] = useState([]);

  // ─── 計算值 ────────────────────────────────────────────────────
  const filteredCount = filterChars(level, selectedRadicals).length;
  const currentItem = quizPool[currentIdx];
  const multiReadings = currentItem?.readings;
  const weaknesses = [...questionTimes].sort((a, b) => b.time - a.time).slice(0, 5);

  // ─── 計時器 ────────────────────────────────────────────────────
  useEffect(() => {
    if (screen !== "quiz" || showResult || isPaused) return;
    if (timerValue === 0) return;

    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1 && timerValue > 0) {
          clearInterval(timerRef.current);
          setShowResult(true);
          return 0;
        }
        return t - 1;
      });
    }, 1000);

    return () => clearInterval(timerRef.current);
  }, [screen, showResult, isPaused, timerValue]);

  // ─── 測驗邏輯 ──────────────────────────────────────────────────
  const startQuiz = useCallback((pool) => {
    if (pool.length === 0) return;
    const q = generateQuestion(pool[0], pool, quizLevelRef.current);
    setQuizPool(pool);
    setCurrentIdx(0);
    setQuestion(q);
    setSelected(null);
    setFirstAttemptCorrect(null);
    setWrongSelections(new Set());
    setScore(0);
    setStreak(0);
    setBestStreak(0);
    setTotal(0);
    setShowResult(false);
    setIsPaused(false);
    setEarlyEnd(false);
    setEarlyEndTime(null);
    setTimeLeft(timerValue);
    setAnimKey(0);
    setQuestionStartTime(Date.now());
    setQuestionTimes([]);
    setScreen("quiz");
  }, [timerValue]);

  const handleStartNormal = () => setScreen("radical-select");

  const handleStartFromRadical = () => {
    const chars = filterChars(level, selectedRadicals);
    if (chars.length === 0) return;
    quizLevelRef.current = level;
    const pool = generateQuizPool(chars, Math.min(chars.length, 999));
    startQuiz(pool);
  };

  const goNext = useCallback(() => {
    const elapsed = Date.now() - (questionStartTime || Date.now());
    setQuestionTimes(prev => [...prev, {
      char: quizPool[currentIdx]?.char,
      zhuyin: quizPool[currentIdx]?.zhuyin,
      time: elapsed,
      correct: firstAttemptCorrect,
    }]);

    const next = currentIdx + 1;
    if (next >= quizPool.length) {
      setShowResult(true);
      return;
    }
    setCurrentIdx(next);
    const q = generateQuestion(quizPool[next], quizPool, quizLevelRef.current);
    setQuestion(q);
    setSelected(null);
    setFirstAttemptCorrect(null);
    setWrongSelections(new Set());
    setAnimKey(k => k + 1);
    setQuestionStartTime(Date.now());
  }, [currentIdx, quizPool, questionStartTime, firstAttemptCorrect]);

  const handleSelect = (opt) => {
    if (!question) return;
    if (selected === question.answer) return;
    if (wrongSelections.has(opt)) return;

    const isCorrect = opt === question.answer;
    if (isCorrect) {
      setSelected(opt);
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(true);
        setScore(s => s + 1);
        setStreak(s => {
          const ns = s + 1;
          setBestStreak(b => Math.max(b, ns));
          return ns;
        });
      }
      setTotal(t => t + 1);
      setTimeout(goNext, 800);
    } else {
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(false);
        setStreak(0);
        setTotal(t => t + 1);
      }
      setWrongSelections(prev => new Set([...prev, opt]));
    }
  };

  const togglePause = () => setIsPaused(p => !p);
  const endGame = (isEarly = false) => {
    clearInterval(timerRef.current);
    if (isEarly) {
      setEarlyEnd(true);
      setEarlyEndTime(formatTime(timeLeft));
    }
    if (quizPool[currentIdx] && questionStartTime) {
      const elapsed = Date.now() - questionStartTime;
      setQuestionTimes(prev => [...prev, {
        char: quizPool[currentIdx].char,
        zhuyin: quizPool[currentIdx].zhuyin,
        time: elapsed,
        correct: firstAttemptCorrect,
      }]);
    }
    setShowResult(true);
    setIsPaused(false);
  };

  const handleImport = () => {
    const parsed = parseMarkdownImport(importText);
    if (parsed.length === 0) return;
    setImportText("");
    quizLevelRef.current = 5;
    startQuiz(parsed);
  };

  // ─── 部首操作 ──────────────────────────────────────────────────
  const toggleRadical = (r) => {
    setSelectedRadicals(prev => {
      const next = new Set(prev);
      if (next.has(r)) next.delete(r); else next.add(r);
      return next;
    });
  };
  const selectAllRadicals = () => setSelectedRadicals(new Set(ALL_RADICALS));
  const clearAllRadicals = () => setSelectedRadicals(new Set());

  // ─── 造字工坊邏輯（全字庫出題）─────────────────────────────────
  const buildForgePool = () => {
    return ALL_CHARS
      .filter(c => c.radical && c.char !== c.radical) // 排除部首本身
      .map(c => ({
        char: c.char,
        radical: c.radical,
        zhuyin: c.zhuyin,
      }));
  };

  const generateForgeQuestion = (pool, idx, allItems) => {
    if (idx >= pool.length) { setForgeResult(true); return; }
    const item = pool[idx];
    // 錯誤選項：從不同部首的字中隨機選 2 個
    const src = allItems || pool;
    const wrongChars = src
      .filter(p => p.radical !== item.radical && p.char !== item.char)
      .sort(() => Math.random() - 0.5)
      .slice(0, 2)
      .map(p => p.char);
    const opts = [item.char, ...wrongChars].sort(() => Math.random() - 0.5);
    setForgeQuestion({
      char: item.char,
      radical: item.radical,
      zhuyin: item.zhuyin,
      answer: item.char,
      options: opts,
    });
    setForgeAnimKey(k => k + 1);
  };

  const startForge = () => {
    const allItems = buildForgePool();
    const shuffled = allItems.sort(() => Math.random() - 0.5);
    setForgePool(shuffled);
    setForgeIdx(0);
    setForgeScore(0);
    setForgeTotal(0);
    setForgeSelected(null);
    setForgeWrongs(new Set());
    setForgeResult(false);
    setForgeAnimKey(0);
    setForgeHistory([]);
    generateForgeQuestion(shuffled, 0, allItems);
    setScreen("forge");
  };

  const handleForgeSelect = (opt) => {
    if (forgeSelected) return;
    if (forgeWrongs.has(opt)) return;
    const isCorrect = opt === forgeQuestion.answer;
    if (isCorrect) {
      setForgeSelected(opt);
      setForgeScore(s => s + 1);
      setForgeTotal(t => t + 1);
      setForgeHistory(prev => [...prev, {
        char: forgeQuestion.char,
        radical: forgeQuestion.radical,
        zhuyin: forgeQuestion.zhuyin,
      }]);
      setTimeout(() => {
        const next = forgeIdx + 1;
        setForgeIdx(next);
        setForgeSelected(null);
        setForgeWrongs(new Set());
        generateForgeQuestion(forgePool, next);
      }, 1200);
    } else {
      setForgeWrongs(prev => new Set([...prev, opt]));
      if (forgeWrongs.size === 0) {
        setForgeTotal(t => t + 1);
      }
    }
  };

  // ─── 變聲秘術邏輯 ──────────────────────────────────────────────
  const POLY_CHARS = ALL_CHARS.filter(c => c.readings && c.readings.length > 1 && c.words && c.words.length >= 2);

  const buildPolyPool = () => {
    const allItems = [];
    POLY_CHARS.forEach(charData => {
      const rCount = charData.readings.length;
      const wCount = charData.words.length;
      const perReading = Math.max(1, Math.floor(wCount / rCount));

      const readingWordMap = charData.readings.map((r, i) => {
        const start = i * perReading;
        const end = i === rCount - 1 ? wCount : start + perReading;
        return { zhuyin: r.zhuyin, pinyin: r.pinyin, words: charData.words.slice(start, end) };
      });

      readingWordMap.forEach(rwm => {
        if (rwm.words.length === 0) return;
        allItems.push({
          char: charData.char,
          zhuyin: rwm.zhuyin,
          word: rwm.words[0],
          sentence: rwm.words.length > 1 ? rwm.words[1] : rwm.words[0],
          allReadings: readingWordMap.map(r => ({ zhuyin: r.zhuyin, word: r.words[0] || '' })),
        });
      });
    });
    return allItems;
  };

  const generatePolyQuestion = (pool, idx, allItems) => {
    if (idx >= pool.length) { setPolyResult(true); return; }
    const item = pool[idx];
    const sameCharWrong = item.allReadings
      .filter(r => r.word && r.word !== item.word)
      .map(r => r.word);
    const src = allItems || pool;
    const otherWords = src
      .filter(p => p.char !== item.char && p.word)
      .map(p => p.word)
      .sort(() => Math.random() - 0.5);
    const finalWrongs = [...new Set([...sameCharWrong.slice(0, 1), ...otherWords])]
      .filter(w => w !== item.word)
      .slice(0, 2);
    const opts = [item.word, ...finalWrongs].sort(() => Math.random() - 0.5);
    setPolyQuestion({
      char: item.char,
      zhuyin: item.zhuyin,
      answer: item.word,
      sentence: item.sentence,
      allReadings: item.allReadings,
      options: opts,
    });
    setPolyAnimKey(k => k + 1);
  };

  const startPolyphone = () => {
    const allItems = buildPolyPool();
    const shuffled = allItems.sort(() => Math.random() - 0.5);
    setPolyPool(shuffled);
    setPolyIdx(0);
    setPolyScore(0);
    setPolyTotal(0);
    setPolySelected(null);
    setPolyWrongs(new Set());
    setPolyResult(false);
    setPolyAnimKey(0);
    setPolyHistory([]);
    generatePolyQuestion(shuffled, 0, allItems);
    setScreen("polyphone");
  };

  const handlePolySelect = (opt) => {
    if (polySelected) return;
    if (polyWrongs.has(opt)) return;
    const isCorrect = opt === polyQuestion.answer;
    if (isCorrect) {
      setPolySelected(opt);
      setPolyScore(s => s + 1);
      setPolyTotal(t => t + 1);
      setPolyHistory(prev => [...prev, {
        char: polyQuestion.char,
        zhuyin: polyQuestion.zhuyin,
        word: polyQuestion.answer,
      }]);
      setTimeout(() => {
        const next = polyIdx + 1;
        setPolyIdx(next);
        setPolySelected(null);
        setPolyWrongs(new Set());
        generatePolyQuestion(polyPool, next);
      }, 1200);
    } else {
      setPolyWrongs(prev => new Set([...prev, opt]));
      if (polyWrongs.size === 0) {
        setPolyTotal(t => t + 1);
      }
    }
  };

  const goHome = () => setScreen("home");

  // ═══════════════════════════════════════════════════════════════
  // RENDER
  // ═══════════════════════════════════════════════════════════════
  return (
    <div className="app">
      {screen === "home" && (
        <HomeScreen
          lang={lang} t={t} setLang={setLang}
          level={level} setLevel={setLevel}
          timerValue={timerValue} setTimerValue={setTimerValue}
          importText={importText} setImportText={setImportText}
          showImportModal={showImportModal} setShowImportModal={setShowImportModal}
          onStartNormal={handleStartNormal}
          onStartForge={startForge}
          onStartPolyphone={startPolyphone}
          onImport={handleImport}
        />
      )}

      {screen === "radical-select" && (
        <RadicalSelect
          lang={lang} t={t}
          selectedRadicals={selectedRadicals}
          radicalSearch={radicalSearch} setRadicalSearch={setRadicalSearch}
          filteredCount={filteredCount}
          onToggleRadical={toggleRadical}
          onSelectAll={selectAllRadicals}
          onClearAll={clearAllRadicals}
          onStartBattle={handleStartFromRadical}
          onBack={goHome}
        />
      )}

      {screen === "quiz" && !showResult && question && currentItem && (
        <QuizScreen
          t={t}
          question={question} currentItem={currentItem}
          currentIdx={currentIdx} quizPool={quizPool}
          score={score} streak={streak}
          timeLeft={timeLeft} timerValue={timerValue}
          selected={selected} wrongSelections={wrongSelections}
          isPaused={isPaused}
          animKey={animKey}
          multiReadings={multiReadings}
          formatTime={formatTime}
          onSelect={handleSelect}
          onTogglePause={togglePause}
          onEndGame={endGame}
        />
      )}

      {screen === "quiz" && showResult && (
        <ResultScreen
          lang={lang} t={t}
          score={score} total={total} bestStreak={bestStreak}
          earlyEnd={earlyEnd} earlyEndTime={earlyEndTime}
          weaknesses={weaknesses}
          onRetry={handleStartNormal}
          onHome={goHome}
        />
      )}

      {screen === "forge" && (
        <ForgeScreen
          lang={lang} t={t}
          forgePool={forgePool} forgeIdx={forgeIdx}
          forgeQuestion={forgeQuestion} forgeSelected={forgeSelected}
          forgeScore={forgeScore} forgeTotal={forgeTotal}
          forgeWrongs={forgeWrongs} forgeResult={forgeResult}
          forgeAnimKey={forgeAnimKey} forgeHistory={forgeHistory}
          onSelect={handleForgeSelect}
          onStartForge={startForge}
          onHome={goHome}
        />
      )}

      {screen === "polyphone" && (
        <PolyphoneScreen
          lang={lang} t={t}
          polyPool={polyPool} polyIdx={polyIdx}
          polyQuestion={polyQuestion} polySelected={polySelected}
          polyScore={polyScore} polyTotal={polyTotal}
          polyWrongs={polyWrongs} polyResult={polyResult}
          polyAnimKey={polyAnimKey} polyHistory={polyHistory}
          onSelect={handlePolySelect}
          onStartPolyphone={startPolyphone}
          onHome={goHome}
        />
      )}
    </div>
  );
}
